INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (1, 'WH-1000XM5', 'Sony', 'Industry-leading noise canceling headphones', 'The Sony WH-1000XM5 features HD Noise Canceling Processor QN2 and Auto NC Optimizer, providing outstanding noise-canceling performance. With 30+ hours of battery life and multipoint connection, it redefines premium wireless audio.', 29990, 34990, 2, '/images/B09XS7JWHH.png', ARRAY['/images/B09XS7JWHH.png', '/images/B098FH5P3C.png', '/images/B09XS7JWHH.png'], '{"Driver Size":"30mm","Frequency Response":"4 Hz – 40,000 Hz","Noise Canceling":"Yes (8 microphones)","Battery Life":"30 hours (NC on)","Charging":"USB-C, 3 min = 3 hours","Connectivity":"Bluetooth 5.2, NFC","Weight":"250g","Microphones":"8 mics"}'::jsonb, 50, 4.8, 12847, true, 'Best Seller') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (2, 'QuietComfort 45', 'Bose', 'Noise cancelling headphones, certified for humans', 'The Bose QuietComfort 45 headphones deliver legendary Bose quiet. TriPort Acoustic architecture and Volume Optimized EQ deliver full, lifelike audio at every volume level. Two modes — Quiet Mode and Aware Mode — keep you in control.', 32000, 37990, 2, '/images/B098FH5P3C.png', ARRAY['/images/B098FH5P3C.png', '/images/B098FH5P3C.png'], '{"Driver Size":"Custom 40mm","Frequency Response":"20 Hz – 20,000 Hz","Noise Canceling":"Yes (Bose Active EQ)","Battery Life":"22 hours","Charging":"USB-C","Connectivity":"Bluetooth 5.1","Weight":"240g","Microphones":"4 mics"}'::jsonb, 35, 4.7, 8923, true, 'Top Rated') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (3, 'AirPods Max', 'Apple', 'A feel-good audio experience', 'AirPods Max combine high-fidelity audio with industry-leading Active Noise Cancellation to deliver an unparalleled listening experience. Each part of AirPods Max has been designed to create an exceptional acoustic system.', 59900, 64900, 1, '/images/B08PZHYWJS.png', ARRAY['/images/B08PZHYWJS.png', '/images/B08PZHYWJS.png'], '{"Driver Size":"40mm Apple-developed dynamic driver","Frequency Response":"20 Hz – 20,000 Hz","Noise Canceling":"Yes (Active Noise Cancellation)","Battery Life":"20 hours","Charging":"USB-C","Connectivity":"Bluetooth 5.0, H1 chip","Weight":"385g","Microphones":"9 mics"}'::jsonb, 20, 4.6, 6210, true, 'Premium') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (4, 'Studio Pro', 'Beats', 'Lossless audio. Zero compromise.', 'Studio Pro delivers personalized spatial audio with dynamic head tracking, lossless audio quality with USB-C, and up to 40 hours of battery life. The professional-grade headphones reimagined for everyday life.', 27900, 31990, 1, '/images/B0C8PRPMXP.png', ARRAY['/images/B0C8PRPMXP.png'], '{"Driver Size":"Custom 40mm","Frequency Response":"20 Hz – 20,000 Hz","Noise Canceling":"Yes (ANC + Transparency)","Battery Life":"40 hours (ANC off)","Charging":"USB-C, 3.5mm","Connectivity":"Bluetooth 5.3, Apple W1 chip","Weight":"260g","Microphones":"4 mics"}'::jsonb, 28, 4.5, 3847, false, null) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (5, 'Quantum 910', 'JBL', 'Head-tracking spatial sound — no console required', 'JBL Quantum 910 features Head-Tracking Spatial Sound that shifts as you move your head, JBL QuantumSPHERE 360 technology, and Active Noise Cancelling. Compatible with PC, console, and mobile.', 14999, 19999, 3, '/images/B0B8T985R9.png', ARRAY['/images/B0B8T985R9.png'], '{"Driver Size":"40mm","Frequency Response":"20 Hz – 20,000 Hz","Microphone":"Detachable boom + beamforming","Battery Life":"34 hours","Charging":"USB-C","Connectivity":"Bluetooth 5.0, 3.5mm, USB","Weight":"340g","Platform":"PC, PS, Xbox, Switch, Mobile"}'::jsonb, 42, 4.4, 2156, true, 'Gaming Pro') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (6, 'Arctis Nova Pro', 'SteelSeries', 'The premium gaming audio benchmark', 'The Arctis Nova Pro Wireless is a premium gaming headset with superior acoustic performance, 360° spatial audio with 2 hot-swap batteries for infinite playtime, and ClearCast AI noise-cancelling mic.', 22999, 27999, 3, '/images/B09ZWKD9TF.png', ARRAY['/images/B09ZWKD9TF.png'], '{"Driver Size":"40mm Hi-Fi","Frequency Response":"10 Hz – 40,000 Hz","Microphone":"Retractable ClearCast AI","Battery Life":"Infinite (hot-swap dual battery)","Charging":"USB-C base","Connectivity":"Bluetooth 5.0 + 2.4GHz lossless","Weight":"338g","Platform":"PC, PS5, PS4"}'::jsonb, 18, 4.7, 4532, false, null) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (7, 'ATH-M50x', 'Audio-Technica', 'Critically acclaimed studio performance', 'The ATH-M50x professional monitor headphones are engineered for studio use and feature outstanding clarity throughout an extended frequency range, with deep, accurate bass response. Legendary for mixing and mastering.', 12990, 15990, 4, '/images/B00HVLUR86.png', ARRAY['/images/B00HVLUR86.png'], '{"Driver Size":"45mm large-aperture","Frequency Response":"15 Hz – 28,000 Hz","Impedance":"38 ohms","Sensitivity":"99 dB","Connectivity":"3.5mm + 6.3mm adapter","Weight":"285g","Cable":"Detachable 3 cables included","Type":"Closed-back, circumaural"}'::jsonb, 60, 4.8, 15600, true, 'Studio Classic') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (8, 'HD 660S2', 'Sennheiser', 'Open-back audiophile excellence', 'The Sennheiser HD 660S2 is an audiophile-grade open-back dynamic headphone with improved bass extension and a highly refined acoustic design. Featuring a new 300-ohm transducer for superior resolution.', 45000, 49990, 4, '/images/B0BRP1F6B1.png', ARRAY['/images/B0BRP1F6B1.png'], '{"Driver Size":"38mm lightweight aluminium voice coil","Frequency Response":"8 Hz – 41,500 Hz","Impedance":"300 ohms","Sensitivity":"104 dB","Connectivity":"6.35mm, 4.4mm balanced, XLR","Weight":"260g","Type":"Open-back, circumaural","THD":"< 0.04% (1 kHz, 100 dB)"}'::jsonb, 12, 4.9, 1823, false, 'Audiophile') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (9, 'WF-1000XM5', 'Sony', 'The best truly wireless earbuds', 'Sony WF-1000XM5 earbuds deliver industry-leading noise canceling in the smallest, lightest design yet. Featuring the HD Noise Canceling Processor QN2e and two Bluetooth chips for superior connectivity.', 19990, 24990, 5, '/images/B0C3HVHMDM.png', ARRAY['/images/B0C3HVHMDM.png'], '{"Driver Size":"8.4mm","Frequency Response":"20 Hz – 40,000 Hz","Noise Canceling":"Yes (Integrated Processor V2)","Battery Life":"8 hours (36 hours with case)","Charging":"USB-C, Qi wireless","Connectivity":"Bluetooth 5.3, Multipoint","Weight":"5.9g each","Water Resistance":"IPX4"}'::jsonb, 45, 4.7, 7234, true, 'Best Earbuds') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (10, 'Galaxy Buds2 Pro', 'Samsung', 'Intelligent ANC. Hi-Fi sound.', 'Galaxy Buds2 Pro packs outstanding audio hardware into a compact ergonomic design. Featuring Intelligent Active Noise Cancellation, 360° Audio with head tracking, and 24-bit Hi-Fi audio.', 14999, 17999, 5, '/images/B0B39RXXSF.png', ARRAY['/images/B0B39RXXSF.png'], '{"Driver Size":"10mm woofer + 6.1mm tweeter","Frequency Response":"20 Hz – 20,000 Hz","Noise Canceling":"Yes (Intelligent ANC)","Battery Life":"5 hours (18 hours with case)","Charging":"USB-C, Qi wireless","Connectivity":"Bluetooth 5.3","Weight":"5.5g each","Water Resistance":"IPX7"}'::jsonb, 38, 4.5, 5678, false, null) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (11, 'Tune 760NC', 'JBL', 'Active Noise Cancelling on a budget', 'JBL Tune 760NC delivers the legendary JBL Pure Bass Sound with Active Noise Cancelling, multi-point connection, and up to 35 hours of battery life. Lightweight, foldable, and available in vibrant colors.', 4999, 7999, 6, '/images/B095X7T381.png', ARRAY['/images/B095X7T381.png'], '{"Driver Size":"40mm","Frequency Response":"20 Hz – 20,000 Hz","Noise Canceling":"Yes (Active)","Battery Life":"35 hours (ANC on)","Charging":"USB-C","Connectivity":"Bluetooth 5.0, multi-point","Weight":"249g","Type":"Closed-back"}'::jsonb, 80, 4.3, 9123, false, 'Best Value') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
INSERT INTO public.products (id, name, brand, tagline, description, price, original_price, category_id, image_url, images, specs, stock, rating, review_count, is_featured, badge) VALUES (12, 'Evolve2 85', 'Jabra', 'Professional wireless headset redefined', 'Jabra Evolve2 85 is the world''s best professional headset. With unprecedented 8-mic technology, Advanced Active Noise Cancellation, and a premium leather memory foam cushion for all-day comfort.', 42000, 47990, 2, '/images/B08761X7L2.png', ARRAY['/images/B08761X7L2.png'], '{"Driver Size":"Custom 40mm","Frequency Response":"20 Hz – 20,000 Hz","Noise Canceling":"Yes (Advanced ANC)","Battery Life":"37 hours","Charging":"USB-C, Qi wireless","Connectivity":"Bluetooth 5.0, USB-A/C dongle","Weight":"340g","Microphones":"8 professional mics"}'::jsonb, 15, 4.6, 1245, false, 'Pro Choice') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, price=EXCLUDED.price, image_url=EXCLUDED.image_url, stock=EXCLUDED.stock;
